148→  double saddlePerpForceRatio; // proportion to keep of the perpendicular force
149→                               // when the lowest eigenvalue is positive
150→  bool saddleNonnegativeDisplacementAbort; // abort the saddle search if the
151→                                           // displacement does not have a
