  66→  MPIPotentialRank = -1;
  67→  LogPotential = false;
  68→  LAMMPSLogging = false;
  69→  LAMMPSThreads = 0;
  70→  EMTRasmussen = false;
  71→  extPotPath = "./ext_pot";
  72→
  73→  // [AMS] //
  74→  engine = "";     // One of REAXFF MOPAC
