  90→
  91→  // [XTBPot] //
  92→  xtb_paramset = "GFNFF";
  93→  xtb_acc = 1.0;
  94→  xtb_elec_temperature = 0.0;
  95→  xtb_maxiter = 250;
  96→  xtb_charge = 0.0;
  97→  xtb_uhf = 0;
  98→
  99→  // [ZBLPot] //
 100→  // NOTE(rg): No good defaults TBH
 101→  zbl_options.cut_inner = 2.0;
 102→  zbl_options.cut_global = 2.5;
 103→
 104→  // [SocketNWChemPot] //
