 109→  // expands to /tmp/ipi_eon_nwchem as per spec
 110→  socket_nwchem_options.unix_socket_path = "eon_nwchem";
 111→  socket_nwchem_options.unix_socket_mode = false;
 112→  socket_nwchem_options.make_template_input = true;
 113→
 114→  // [Structure Comparison] //
 115→  distanceDifference = 0.1;
 116→  neighborCutoff = 3.3;
 117→  checkRotation = false;
 118→  indistinguishableAtoms = true;
