 485→int Parameters::load(FILE *file) {
 486→
 487→  CIniFile ini;
 488→  ini.CaseInsensitive();
 489→  int error = 0;
 490→
 491→  if (ini.ReadFile(file)) {
 492→
 493→    // [Main] //
 494→
 495→    job = magic_enum::enum_cast<JobType>(ini.GetValue("Main", "job"),
 496→                                         magic_enum::case_insensitive)
 497→              .value_or(JobType::Unknown);
 498→    temperature = ini.GetValueF("Main", "temperature", temperature);
 499→    randomSeed = ini.GetValueL("Main", "random_seed", randomSeed);
 500→    checkpoint = ini.GetValueB("Main", "checkpoint", checkpoint);
 501→    quiet = ini.GetValueB("Main", "quiet", quiet);
 502→    writeLog = ini.GetValueB("Main", "write_log", writeLog);
 503→    finiteDifference =
 504→        ini.GetValueF("Main", "finite_difference", finiteDifference);
 505→    // Initialize random generator
 506→    if (randomSeed < 0) {
 507→      unsigned i = time(NULL);
 508→      randomSeed = i;
 509→      helper_functions::random(i);
 510→    } else {
 511→      helper_functions::random(randomSeed);
 512→    }
 513→    maxForceCalls = ini.GetValueL("Main", "max_force_calls", maxForceCalls);
 514→    removeNetForce = ini.GetValueB("Main", "remove_net_force", removeNetForce);
 515→
 516→    // [Potential] //
 517→
 518→    potential =
 519→        magic_enum::enum_cast<PotType>(ini.GetValue("Potential", "potential"),
 520→                                       magic_enum::case_insensitive)
 521→            .value_or(PotType::UNKNOWN);
 522→    MPIPollPeriod =
 523→        ini.GetValueF("Potential", "mpi_poll_period", MPIPollPeriod);
 524→    LAMMPSLogging = ini.GetValueB("Potential", "lammps_logging", LAMMPSLogging);
 525→    LAMMPSThreads =
 526→        (int)ini.GetValueL("Potential", "lammps_threads", LAMMPSThreads);
 527→    EMTRasmussen = ini.GetValueB("Potential", "emt_rasmussen", EMTRasmussen);
 528→    extPotPath = ini.GetValue("Potential", "ext_pot_path", extPotPath);
 529→
 530→    if (potential == PotType::MPI || potential == PotType::VASP ||
 531→        potential == PotType::BOPFOX || potential == PotType::BOP) {
 532→      LogPotential = true;
 533→    } else {
 534→      LogPotential = false;
 535→    }
 536→    LogPotential = ini.GetValueB("Potential", "log_potential", LogPotential);
 537→
 538→    // [AMS]
 539→    if (potential == PotType::AMS) {
 540→      engine = ini.GetValue("AMS", "engine", engine);
 541→      forcefield = ini.GetValue("AMS", "forcefield", forcefield);
 542→      resources = ini.GetValue("AMS", "resources", resources);
 543→      model = ini.GetValue("AMS", "model", model);
 544→      xc = ini.GetValue("AMS", "xc", xc);
 545→      basis = ini.GetValue("AMS", "basis", basis);
 546→    }
 547→    // [AMS_IO]
 548→    if (potential == PotType::AMS_IO) {
 549→      engine = ini.GetValue("AMS_IO", "engine", engine);
 550→      forcefield = ini.GetValue("AMS_IO", "forcefield", forcefield);
 551→      model = ini.GetValue("AMS_IO", "model", model);
 552→      xc = ini.GetValue("AMS_IO", "xc", xc);
 553→    }
 554→    // [AMS_ENV]
 555→    // This is only needed if the regular calls do not work
 556→    // e.g. on a MacOS machine
 557→    if (potential == PotType::AMS_IO || potential == PotType::AMS) {
 558→      amshome = ini.GetValue("AMS_ENV", "amshome", amshome);
 559→      scm_tmpdir = ini.GetValue("AMS_ENV", "scm_tmpdir", scm_tmpdir);
 560→      scmlicense = ini.GetValue("AMS_ENV", "scmlicense", scmlicense);
 561→      scm_pythondir = ini.GetValue("AMS_ENV", "scm_pythondir", scm_pythondir);
 562→      amsbin = ini.GetValue("AMS_ENV", "amsbin", amsbin);
 563→      amsresources = ini.GetValue("AMS_ENV", "amsresources", amsresources);
 564→    }
 565→    // [XTBPot]
 566→    if (potential == PotType::XTB) {
 567→      xtb_paramset = ini.GetValue("XTBPot", "paramset", xtb_paramset);
 568→      xtb_acc = ini.GetValueF("XTBPot", "accuracy", xtb_acc);
 569→      xtb_elec_temperature = ini.GetValueF("XTBPot", "electronic_temperature",
 570→                                           xtb_elec_temperature);
 571→      xtb_maxiter = ini.GetValueL("XTBPot", "max_iterations", xtb_maxiter);
 572→      xtb_uhf = ini.GetValueL("XTBPot", "uhf", xtb_uhf);
 573→      xtb_charge = ini.GetValueF("XTBPot", "charge", xtb_charge);
 574→    }
 575→    // [ZBLPot]
 576→    if (potential == PotType::ZBL) {
 577→      zbl_options.cut_inner =
 578→          ini.GetValueF("ZBLPot", "cut_inner", zbl_options.cut_inner);
 579→      zbl_options.cut_global =
 580→          ini.GetValueF("ZBLPot", "cut_global", zbl_options.cut_global);
 581→      if (zbl_options.cut_inner > zbl_options.cut_global) {
 582→        throw std::runtime_error(
 583→            "Switching function must begin before the global cutoff!");
 584→      }
 585→    }
 586→    // [SocketNWChemPot]
 587→    if (potential == PotType::SocketNWChem) {
 588→      socket_nwchem_options.host =
 589→          ini.GetValue("SocketNWChemPot", "host", socket_nwchem_options.host);
 590→      socket_nwchem_options.port =
 591→          ini.GetValueL("SocketNWChemPot", "port", socket_nwchem_options.port);
 592→      socket_nwchem_options.mem_in_gb = ini.GetValueL(
 593→          "SocketNWChemPot", "mem_in_gb", socket_nwchem_options.mem_in_gb);
 594→      socket_nwchem_options.nwchem_settings =
 595→          ini.GetValue("SocketNWChemPot", "nwchem_settings",
 596→                       socket_nwchem_options.nwchem_settings);
 597→      socket_nwchem_options.unix_socket_path =
 598→          ini.GetValue("SocketNWChemPot", "unix_socket_path",
 599→                       socket_nwchem_options.unix_socket_path);
 600→      socket_nwchem_options.unix_socket_mode =
 601→          ini.GetValueB("SocketNWChemPot", "unix_socket_mode",
 602→                        socket_nwchem_options.unix_socket_mode);
 603→      socket_nwchem_options.make_template_input =
 604→          ini.GetValueB("SocketNWChemPot", "make_template_input",
 605→                        socket_nwchem_options.make_template_input);
 606→    }
 607→
 608→    // [Debug] //
 609→
 610→    writeMovies = ini.GetValueB("Debug", "write_movies", writeMovies);
 611→    writeMoviesInterval =
 612→        ini.GetValueL("Debug", "write_movies_interval", writeMoviesInterval);
 613→    estNEBeig = ini.GetValueB("Debug", "estimate_neb_eigenvalues", estNEBeig);
 614→    nebMMF = toLowerCase(ini.GetValue("Debug", "neb_mmf_estimator", nebMMF));
 615→
 616→    // [Structure Comparison] //
 617→
 618→    distanceDifference = ini.GetValueF(
 619→        "Structure Comparison", "distance_difference", distanceDifference);
 620→    neighborCutoff = ini.GetValueF("Structure Comparison", "neighbor_cutoff",
 621→                                   neighborCutoff);
 622→    checkRotation =
 623→        ini.GetValueB("Structure Comparison", "check_rotation", checkRotation);
 624→    energyDifference = ini.GetValueF("Structure Comparison",
 625→                                     "energy_difference", energyDifference);
 626→    indistinguishableAtoms =
 627→        ini.GetValueB("Structure Comparison", "indistinguishable_atoms",
 628→                      indistinguishableAtoms);
 629→    removeTranslation = ini.GetValueB("Structure Comparison",
 630→                                      "remove_translation", removeTranslation);
 631→
 632→    // [Process Search] //
 633→
 634→    processSearchMinimizeFirst = ini.GetValueB(
