1113→    parrepStateCheckIntervalInput =
1114→        ini.GetValueF("Parallel Replica", "state_check_interval",
1115→                      parrepStateCheckIntervalInput);
1116→    parrepStateCheckInterval = parrepStateCheckIntervalInput / timeUnit;
1117→    parrepRecordIntervalInput =
1118→        ini.GetValueF("Parallel Replica", "state_save_interval",
1119→                      0.1 * parrepStateCheckIntervalInput);
1120→    parrepRecordInterval = parrepRecordIntervalInput / timeUnit;
1121→    parrepCorrTimeInput = ini.GetValueF(
1122→        "Parallel Replica", "post_transition_time", parrepCorrTimeInput);
1123→    parrepCorrTime = parrepCorrTimeInput / timeUnit;
1124→
1125→    //[Temperature Accelerated Dynamics] //
1126→
1127→    tadLowT = ini.GetValueF("TAD", "low_temperature", tadLowT);
1128→    tadMinPrefactor = ini.GetValueF("TAD", "min_prefactor", tadMinPrefactor);
1129→    tadConfidence = ini.GetValueF("TAD", "confidence", tadConfidence);
1130→
1131→    // [Replica Exchange] //
1132→
1133→    repexcTemperatureDistribution =
1134→        toLowerCase(ini.GetValue("Replica Exchange", "temperature_distribution",
1135→                                 repexcTemperatureDistribution));
1136→    repexcReplicas =
1137→        ini.GetValueL("Replica Exchange", "replicas", repexcReplicas);
1138→    repexcExchangeTrials = ini.GetValueL("Replica Exchange", "exchange_trials",
1139→                                         repexcExchangeTrials);
1140→    repexcSamplingTimeInput = ini.GetValueF("Replica Exchange", "sampling_time",
1141→                                            repexcSamplingTimeInput);
1142→    repexcSamplingTime = repexcSamplingTimeInput / timeUnit;
1143→    repexcTemperatureLow =
1144→        ini.GetValueF("Replica Exchange", "temperature_low", temperature);
1145→    repexcTemperatureHigh = ini.GetValueF(
1146→        "Replica Exchange", "temperature_high", repexcTemperatureHigh);
1147→    repexcExchangePeriodInput = ini.GetValueF(
1148→        "Replica Exchange", "exchange_period", repexcExchangePeriodInput);
1149→    repexcExchangePeriod = repexcExchangePeriodInput / timeUnit;
1150→
1151→    // [Hyperdynamics] //
1152→
1153→    bondBoostRMDTimeInput =
