1184→    saddleMaxSingleDisplace = ini.GetValueF(
1185→        "Saddle Search", "max_single_displace", saddleMaxSingleDisplace);
1186→    // must be loaded after optConvergedForce
1187→    saddleConvergedForce =
1188→        ini.GetValueF("Saddle Search", "converged_force", optConvergedForce);
1189→    saddlePerpForceRatio = ini.GetValueF("Saddle Search", "perp_force_ratio",
1190→                                         saddlePerpForceRatio); // undocumented
1191→    saddleDisplaceType = toLowerCase(ini.GetValue(
1192→        "Saddle Search", "client_displace_type", EpiCenters::DISP_LOAD));
1193→    saddleNonlocalCountAbort =
1194→        ini.GetValueL("Saddle Search", "nonlocal_count_abort",
1195→                      saddleNonlocalCountAbort); // undocumented
1196→    saddleNonlocalDistanceAbort =
1197→        ini.GetValueF("Saddle Search", "nonlocal_distance_abort",
1198→                      saddleNonlocalDistanceAbort); // undocumented
1199→    if (saddleDisplaceType != EpiCenters::DISP_NOT_FCC_OR_HCP &&
1200→        saddleDisplaceType != EpiCenters::DISP_MIN_COORDINATED &&
1201→        saddleDisplaceType != EpiCenters::DISP_LAST_ATOM &&
1202→        saddleDisplaceType != EpiCenters::DISP_RANDOM) {
1203→      saddleDisplaceType = EpiCenters::DISP_LOAD;
1204→    }
1205→    saddleConfinePositive = ini.GetValueB("Saddle Search", "confine_positive",
1206→                                          saddleConfinePositive);
1207→    if (saddleConfinePositive) {
1208→      saddleBowlBreakout =
1209→          ini.GetValueB("Saddle Search", "bowl_breakout", saddleBowlBreakout);
1210→      saddleBowlActive =
1211→          ini.GetValueL("Saddle Search", "bowl_active_atoms", saddleBowlActive);
1212→      saddleConfinePositiveMinForce =
1213→          ini.GetValueF("Saddle Search", "confine_positive_min_move",
1214→                        saddleConfinePositiveMinForce);
1215→      saddleConfinePositiveScaleRatio =
1216→          ini.GetValueF("Saddle Search", "confine_positive_scale_ratio",
1217→                        saddleConfinePositiveScaleRatio);
1218→      saddleConfinePositiveBoost =
1219→          ini.GetValueF("Saddle Search", "confine_positive_boost",
1220→                        saddleConfinePositiveBoost);
1221→      saddleConfinePositiveMinActive =
1222→          ini.GetValueL("Saddle Search", "confine_positive_min_active",
1223→                        saddleConfinePositiveMinActive);
1224→    }
1225→    saddleDynamicsTemperature = temperature;
1226→    saddleDynamicsTemperature = ini.GetValueF(
1227→        "Saddle Search", "dynamics_temperature", saddleDynamicsTemperature);
1228→    saddleDynamicsStateCheckIntervalInput =
1229→        ini.GetValueF("Saddle Search", "dynamics_state_check_interval",
1230→                      saddleDynamicsStateCheckIntervalInput);
1231→    saddleDynamicsStateCheckInterval =
1232→        saddleDynamicsStateCheckIntervalInput / timeUnit;
1233→    saddleDynamicsRecordIntervalInput =
1234→        ini.GetValueF("Saddle Search", "dynamics_record_interval",
1235→                      saddleDynamicsRecordIntervalInput);
1236→    saddleDynamicsRecordInterval = saddleDynamicsRecordIntervalInput / timeUnit;
1237→    saddleDynamicsLinearInterpolation =
1238→        ini.GetValueB("Saddle Search", "dynamics_linear_interpolation",
1239→                      saddleDynamicsLinearInterpolation);
1240→    saddleRemoveRotation =
1241→        ini.GetValueB("Saddle Search", "remove_rotation", saddleRemoveRotation);
1242→    saddleDynamicsMaxInitCurvature =
1243→        ini.GetValueF("Saddle Search", "dynamics_max_init_curvature",
1244→                      saddleDynamicsMaxInitCurvature);
1245→    saddleZeroModeAbortCurvature =
1246→        ini.GetValueF("Saddle Search", "zero_mode_abort_curvature",
1247→                      saddleZeroModeAbortCurvature);
1248→
1249→    // [Basin Hopping] //
1250→
1251→    basinHoppingDisplacement = ini.GetValueF("Basin Hopping", "displacement",
1252→                                             basinHoppingDisplacement);
1253→    basinHoppingPushApartDistance = ini.GetValueF(
1254→        "Basin Hopping", "push_apart_distance", basinHoppingPushApartDistance);
1255→    basinHoppingInitialRandomStructureProbability =
1256→        ini.GetValueF("Basin Hopping", "initial_random_structure_probability",
1257→                      basinHoppingInitialRandomStructureProbability);
1258→    basinHoppingSteps =
1259→        ini.GetValueL("Basin Hopping", "steps", basinHoppingSteps);
1260→    basinHoppingQuenchingSteps = ini.GetValueL(
1261→        "Basin Hopping", "quenching_steps", basinHoppingQuenchingSteps);
1262→    basinHoppingSingleAtomDisplace =
1263→        ini.GetValueB("Basin Hopping", "single_atom_displace",
1264→                      basinHoppingSingleAtomDisplace);
1265→    basinHoppingSignificantStructure =
1266→        ini.GetValueB("Basin Hopping", "significant_structure",
1267→                      basinHoppingSignificantStructure);
1268→    basinHoppingDisplacementAlgorithm =
1269→        toLowerCase(ini.GetValue("Basin Hopping", "displacement_algorithm",
