1271→    basinHoppingDisplacementDistribution =
1272→        toLowerCase(ini.GetValue("Basin Hopping", "displacement_distribution",
1273→                                 basinHoppingDisplacementDistribution));
1274→    basinHoppingSwapProbability = ini.GetValueF(
1275→        "Basin Hopping", "swap_probability", basinHoppingSwapProbability);
1276→    basinHoppingJumpMax =
1277→        ini.GetValueL("Basin Hopping", "jump_max", basinHoppingJumpMax);
1278→    basinHoppingJumpSteps =
1279→        ini.GetValueL("Basin Hopping", "jump_steps", basinHoppingJumpSteps);
1280→    basinHoppingAdjustDisplacement = ini.GetValueB(
1281→        "Basin Hopping", "adjust_displacement", basinHoppingAdjustDisplacement);
1282→    basinHoppingAdjustPeriod = ini.GetValueL("Basin Hopping", "adjust_period",
1283→                                             basinHoppingAdjustPeriod);
1284→    basinHoppingAdjustFraction = ini.GetValueF(
1285→        "Basin Hopping", "adjust_fraction", basinHoppingAdjustFraction);
1286→    basinHoppingTargetRatio =
1287→        ini.GetValueF("Basin Hopping", "target_ratio", basinHoppingTargetRatio);
1288→    basinHoppingWriteUnique =
1289→        ini.GetValueB("Basin Hopping", "write_unique", basinHoppingWriteUnique);
1290→    basinHoppingStopEnergy =
1291→        ini.GetValueF("Basin Hopping", "stop_energy", basinHoppingStopEnergy);
1292→
1293→    // [Global Optimization] //
1294→
1295→    globalOptimizationMoveMethod = toLowerCase(ini.GetValue(
1296→        "Global Optimization", "move_method", globalOptimizationMoveMethod));
1297→    globalOptimizationDecisionMethod =
1298→        toLowerCase(ini.GetValue("Global Optimization", "decision_method",
1299→                                 globalOptimizationDecisionMethod));
1300→    globalOptimizationSteps =
1301→        ini.GetValueL("Global Optimization", "steps", globalOptimizationSteps);
1302→    globalOptimizationBeta =
1303→        ini.GetValueF("Global Optimization", "beta", globalOptimizationBeta);
1304→    globalOptimizationAlpha =
1305→        ini.GetValueF("Global Optimization", "alpha", globalOptimizationAlpha);
1306→    globalOptimizationMdmin =
1307→        ini.GetValueL("Global Optimization", "mdmin", globalOptimizationMdmin);
1308→    globalOptimizationTargetEnergy = ini.GetValueF(
1309→        "Global Optimization", "target_energy", globalOptimizationTargetEnergy);
1310→
1311→    // [BGSD] //
1312→
1313→    alpha = ini.GetValueF("BGSD", "alpha", alpha);
1314→    beta = ini.GetValueF("BGSD", "beta", beta);
1315→    gradientfinitedifference = ini.GetValueF("BGSD", "gradientfinitedifference",
1316→                                             gradientfinitedifference);
1317→    grad2energyconvergence =
1318→        ini.GetValueF("BGSD", "grad2energyconvergence", grad2energyconvergence);
1319→    grad2forceconvergence =
1320→        ini.GetValueF("BGSD", "grad2forceconvergence", grad2forceconvergence);
1321→
1322→    // [Monte Carlo] //
1323→
1324→    monteCarloStepSize =
1325→        ini.GetValueF("Monte Carlo", "step_size", monteCarloStepSize);
1326→    monteCarloSteps = ini.GetValueI("Monte Carlo", "steps", monteCarloSteps);
1327→
1328→    // Sanity Checks
1329→    if (parrepStateCheckInterval > mdTime &&
1330→        magic_enum::enum_name<JobType>(job) == "parallel_replica") {
1331→      SPDLOG_ERROR("[Parallel Replica] state_check_interval must be <= time");
1332→      error = 1;
1333→    }
1334→
1335→    // Check if an initial path exists without a specific non-linear initializer
1336→    if (!neb_options.initialization.input_path.empty() &&
1337→        neb_options.initialization.method == NEBInit::LINEAR) {
1338→      SPDLOG_WARN("[Nudged Elastic Band] 'initial_path_in' is provided, but "
1339→                  "'initializer' defaults to linear. "
1340→                  "Ensure this is intentional, as the loaded path will not be "
1341→                  "used without initializer set to file.");
1342→    }
1343→
1344→    if (saddleDynamicsRecordIntervalInput >
1345→        saddleDynamicsStateCheckIntervalInput) {
1346→      SPDLOG_ERROR("[Saddle Search] dynamics_record_interval must be <= "
1347→                   "dynamics_state_check_interval");
1348→      error = 1;
1349→    }
1350→
1351→    if (potential == PotType::AMS || potential == PotType::AMS_IO) {
1352→      if (forcefield.empty() && model.empty() && xc.empty()) {
1353→        SPDLOG_ERROR("[AMS] Must provide atleast forcefield or model or xc");
1354→        error = 1;
1355→      }
1356→
1357→      if (!forcefield.empty() && !model.empty() && !xc.empty()) {
1358→        SPDLOG_ERROR("[AMS] Must provide either forcefield or model");
1359→        error = 1;
1360→      }
1361→    }
1362→
1363→  } else {
1364→    SPDLOG_ERROR("Couldn't parse the ini file");
1365→    error = 1;
1366→  }
1367→
1368→  return error;
1369→}
