  lanczosTolerance = 0.01;
  lanczosMaxIterations = 20;
  lanczosQuitEarly = true;

  // [GPR Dimer] //
  gprDimerRotationAngle = 0.005;
  gprDimerConvergedAngle = 0.08;     // T_anglerot_init
  gprDimerRelaxConvAngle = 0.001;    // T_anglerot_gp
