425→      bool use_old_tangent;  // Algorithm choice for the local tangent estimate
426→      double trigger_force;  // Force threshold to activate the CI-NEB algorithm
427→      double trigger_factor; // relative factor
428→
429→      struct hybrid_dimer_t {
430→        bool use_mmf; // Integrates Min-Mode Following (MMF) for saddle point
431→                      // refinement
432→        double trigger_force; // Force threshold to activate hybrid dimer search
433→        long max_steps;       // Maximum steps for the MMF refinement phase
434→        long ci_stability_count; // Number of stable iterations before settling
435→                                 // on a CI for MMF
436→        double angle_tol;        // Angular tolerance for the dimer rotation
437→        double trigger_factor;   // relative factor
438→        struct roneb_penalty_t {
439→          // penalty_factor = base + (strength * alignment);
440→          // std::abs(finalMode.normalized().dot(currentTangent.normalized()))
441→          double strength; // amount by which the threshold is reduced
442→          double base;     // baseline
443→        } penalty;
444→      } roneb;
445→    } climbing_image;
446→
447→    struct path_initialization_t {
448→      NEBInit method; // Method for generating the initial guess (e.g., IDPP)
449→      std::string
450→          input_path;     // Path to a file containing initial image coordinates
451→      int max_iterations; // Maximum iterations for the path pre-optimizer
452→      int nsteps;         // Iterations for the path pre-optimizer
453→      double max_move;    // Maximum displacement per step during initialization
454→      double force_tolerance; // Convergence criterion for the initial path
455→                              // generation
456→      double sidpp_alpha; // Growth parameter for Steepest Intensity Decent Path
457→                          // Probing
458→      OptType opt_method; // for the IDPP
459→      bool oversampling;
460→      int oversampling_factor;
461→    } initialization;
462→
463→    struct endpoint_options_t {
464→      bool minimize; // Flag to optimize the reactant and product geometries
465→                     // first
466→      bool use_path_file; // Pull endpoint geometries from the initial path file
467→    } endpoints;
468→
469→  } neb_options;
470→
471→  // [Molecular Dynamics] //
472→  double mdTimeStepInput;
473→  double mdTimeStep;
474→  double mdTimeInput;
475→  double mdTime;
476→  long mdSteps;
477→
478→  // [Parallel Replica] //
479→  bool parrepRefineTransition;
480→  bool parrepAutoStop;
481→  bool parrepDephaseLoopStop;
482→  double parrepDephaseTimeInput;
483→  double parrepDephaseTime;
484→  long parrepDephaseLoopMax;
485→  double parrepStateCheckIntervalInput;
486→  double parrepStateCheckInterval;
487→  double parrepRecordIntervalInput;
488→  double parrepRecordInterval;
489→  double parrepCorrTimeInput;
490→  double parrepCorrTime;
491→
492→  // [Temperature Accelerated Dynamics] //
493→  double tadLowT;
494→  double tadMinPrefactor;
495→  double tadConfidence;
496→
497→  // [Thermostat] //
498→  string thermostat;
499→  double thermoAndersenAlpha;
500→  double thermoAndersenTcolInput;
501→  double thermoAndersenTcol;
502→  double thermoNoseMass;
503→  double thermoLangevinFrictionInput;
504→  double thermoLangevinFriction;
505→  // std::vector<int> thermoAtoms;
506→
