508→  string repexcTemperatureDistribution;
509→  long repexcReplicas;
510→  long repexcExchangeTrials;
511→  double repexcSamplingTimeInput;
512→  double repexcSamplingTime;
513→  double repexcTemperatureHigh;
514→  double repexcTemperatureLow;
