   474→int Parameters::load(string filename) {
   475→  FILE *fh;
   476→
   477→  fh = fopen(filename.c_str(), "rb");
   478→  if (fh == NULL) {
   479→    fprintf(stderr, "error: %s\n", strerror(errno));
   480→    return 1;
   481→  }
   482→  int error = load(fh);
   483→  fclose(fh);
   484→  return error;
   485→}
