  gprDimerPriorSigma2 = 1;        // prior_s2
  gprDimerPriorNu = 20;           // prior_nu
  // GPR Optimization Parameters
  gprOptCheckDerivatives = false; // check_derivative
  gprOptMaxIterations = 400;      // max_iter
